import { useEffect, useState } from "react";
import api from "../api";
const money = n => (Number(n||0)).toLocaleString("vi-VN")+" ₫";

export default function Reports() {
    const [contracts, setContracts] = useState([]);
    const [customers, setCustomers] = useState([]);

    useEffect(()=>{
        (async ()=>{
            const [cts, cus] = await Promise.all([api.get("/api/contracts"), api.get("/api/customers")]);
            setContracts(cts.data||[]);
            setCustomers(cus.data||[]);
        })();
    },[]);

    const sumByGroup = () => {
        const byId = Object.fromEntries(customers.map(c=>[c.id, c]));
        const agg = {};
        contracts.forEach(ct=>{
            const g = byId[ct.customerId]?.group || "Khác";
            agg[g] = (agg[g]||0) + Number(ct.totalAmount||0);
        });
        return Object.entries(agg);
    };

    return (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <div className="p-5 rounded-2xl bg-white shadow border border-indigo-100">
                <div className="font-semibold mb-3">Tổng giá trị theo nhóm</div>
                <div className="space-y-3">
                    {sumByGroup().map(([g,sum])=>(
                        <div key={g} className="p-3 rounded-xl border border-indigo-100 flex items-center justify-between">
                            <div className="font-medium">{g}</div>
                            <div className="font-semibold">{money(sum)}</div>
                        </div>
                    ))}
                    {sumByGroup().length===0 && <div className="text-sm text-slate-500">Không có dữ liệu</div>}
                </div>
            </div>
            <div className="p-5 rounded-2xl bg-white shadow border border-indigo-100">
                <div className="font-semibold mb-3">Ghi chú</div>
                <p className="text-sm text-slate-600">Trang demo báo cáo đơn giản.</p>
            </div>
        </div>
    );
}
